# Expectation survey: quantitative trust calibration at scale
# Run with 40–100 participants before launch

SURVEY_ITEMS = {
    "expected_accuracy": {
        "question": "When the AI assistant summarises an FNOL claim, how often do you expect it to be fully accurate?",
        "scale": "1 = almost never, 5 = almost always",
        "interpretation": {
            "mean < 2.5": "Population expects poor AI quality — launch with intensive human review layer",
            "mean 2.5–3.5": "Mixed expectations — calibration training required",
            "mean > 3.5": "High expectations — over-trust risk; set realistic accuracy communication",
        },
    },
    "acceptable_error_rate": {
        "question": "How often would the AI summary need to be wrong before you stopped relying on it?",
        "scale": "Open response: 'I'd stop trusting it if it was wrong ___ in every 10 summaries'",
        "interpretation": {
            "median ≤ 1": "Very low tolerance — accuracy NFR should be ≥ 90%; high catch-rate needed",
            "median 2–3": "Moderate tolerance — 70–80% accuracy sufficient if errors are non-critical",
            "median ≥ 4": "High tolerance — risk of automation bias; add mandatory spot-check requirement",
        },
    },
    "verification_intention": {
        "question": "After the AI processes a claim, which parts would you always verify manually?",
        "scale": "Checklist: claim type, date, coverage, damage description, claimant details, third-party details",
        "interpretation": "Items checked by < 40% of respondents are at high automation bias risk in production",
    },
}

# Calibration interventions by observed trust level

CALIBRATION_INTERVENTIONS = {

    TrustLevel.AUTOMATION_BIAS: {
        "indicators": [
            "Accepts AI output without reading",
            "Missed 2+ planted errors in error injection study",
            "Stated accuracy expectation > 4.0 / 5.0",
        ],
        "ux_interventions": [
            "Mandatory verification checkpoint for high-stakes fields (coverage, severity)",
            "AI confidence score displayed — low-confidence outputs require explicit confirm",
            "Random spot-check prompts: 'Please verify this against the original submission'",
        ],
        "training_interventions": [
            "Error case library: examples of past AI mistakes with consequences",
            "Spot-check habit: daily 10% verification requirement for first 90 days",
        ],
        "requirements_impact": [
            "NFR: UI must not allow submission of critical-field output without verification step",
            "NFR: Low-confidence outputs (< 0.75) must surface warning before user proceeds",
        ],
    },

    TrustLevel.DISTRUST: {
        "indicators": [
            "Ignores AI output entirely; re-enters from source",
            "Caught every error but spent 3× more time than calibrated users",
            "Stated accuracy expectation < 2.0 / 5.0",
        ],
        "ux_interventions": [
            "Side-by-side view: AI summary alongside original submission text",
            "Explicit accuracy statistics displayed: '94% of fields correct in last 30 days'",
            "Highlight verified fields green after user confirms — builds progressive trust",
        ],
        "training_interventions": [
            "Accuracy evidence review: show real accuracy data from comparable deployments",
            "Supervised pilot: team lead reviews first 20 AI-assisted claims with handler",
        ],
        "requirements_impact": [
            "FR: Side-by-side comparison view is mandatory for launch",
            "FR: Accuracy statistics banner shown for first 30 days per user",
        ],
    },

}
